<template>
  <a :href="linkUrl" class="homeLink col-12 col-lg-6">
    <img :src="require(`@/assets/${img}.jpg`)" />
    <p>{{ title }}</p>
    <p class="instruction" v-html="instruction"></p>
  </a>
</template>

<script>
import { BASE_URL } from '@/utils/constants.js'
export default {
  name: 'Card',
  props: {
    title: {
      type: String,
      required: true
    },
    instruction: {
      type: String,
      default: ''
    },
    img: {
      type: String,
      required: true
    },
    link: {
      type: String,
      required: true
    }
  },
  computed: {
    linkUrl: function() {
      return BASE_URL + this.link
    }
  }
}
</script>

